class Solution(object):
    def minChanges(self, s):
        # Any valid partition can be decomposed into blocks of size 2.
        # For each pair (s[2i], s[2i+1]), if they differ, we need 1 change.
        ops = 0
        for i in range(0, len(s), 2):
            if s[i] != s[i + 1]:
                ops += 1
        return ops
